// Noncompliant - nested switch statements
switch (outerValue)
{
    case 1:
        switch (innerValue) // Noncompliant - nested switch
        {
            case "a":
                // ...
                break;
            case "b":
                // ...
                break;
        }
        break;
    case 2:
        // ...
        break;
}

compliant:
// Compliant - extract inner switch to separate method
switch (outerValue)
{
    case 1:
        HandleInnerValue(innerValue);
        break;
    case 2:
        // ...
        break;
}

private void HandleInnerValue(string innerValue)
{
    switch (innerValue)
    {
        case "a":
            // ...
            break;
        case "b":
            // ...
            break;
    }
}
